97	                Ok(Some(s)) => String::from_utf8_lossy(s.as_bytes()).into_owned(),
98	                _ => "(no error message on stack)".to_string(),
99	            };
100	            return Err(format!(
101	                "Syntax: {} (load_string status={})",
102	                msg, status
103	            ));
104	        }
105	
106	        eprintln!("[4/4] Executing chunk...");
