726	pub fn check_integer(state: &mut LuaState, arg: i32) -> Result<i64, LuaError> {
727	    // C: int isnum; lua_Integer d = lua_tointegerx(L, arg, &isnum);
728	    match state.to_integer_x(arg) {
729	        Some(d) => Ok(d),
730	        None => {
