    /// C: *t — table descriptor (copied; see PORT NOTE above)
    pub t: ExprDesc,
    /// C: nh — total number of record elements
    pub nh: i32,
    /// C: na — number of array elements already stored
    pub na: i32,
    /// C: tostore — array elements pending store
    pub tostore: i32,
}

